Hi,

Sorry for the delay.
Patch is working perfectly and solves the problem.

Thanks,
Aurélien


----- Original Message ----- 
From: "John Baldwin" <jhb@FreeBSD.org>
To: <bug-followup@freebsd.org>; <freebsd@amc-os.com>
Sent: Monday, August 31, 2009 5:05 PM
Subject: Re: kern/137668: amdpm(4) no longer attaches in RELENG_7 - 
7.2-RELEASE ok [regression]


> I've checked a few other OS's and they do not seem to check the value of 
> the
> command register after doing a write.  Can you verify that this patch 
> fixes
> amdpm0 for you?
>
> --- //depot/vendor/freebsd/src/sys/dev/pci/pci.c 2009/07/21 19:10:13
> +++ //depot/user/jhb/acpipci/dev/pci/pci.c 2009/08/31 15:02:19
> @@ -2149,62 +2158,38 @@
> int
> pci_enable_io_method(device_t dev, device_t child, int space)
> {
> - uint16_t command;
>  uint16_t bit;
> - char *error;
> -
> - bit = 0;
> - error = NULL;
>
>  switch(space) {
>  case SYS_RES_IOPORT:
>  bit = PCIM_CMD_PORTEN;
> - error = "port";
>  break;
>  case SYS_RES_MEMORY:
>  bit = PCIM_CMD_MEMEN;
> - error = "memory";
>  break;
>  default:
>  return (EINVAL);
>  }
>  pci_set_command_bit(dev, child, bit);
> - /* Some devices seem to need a brief stall here, what do to? */
> - command = PCI_READ_CONFIG(dev, child, PCIR_COMMAND, 2);
> - if (command & bit)
> - return (0);
> - device_printf(child, "failed to enable %s mapping!\n", error);
> - return (ENXIO);
> + return (0);
> }
>
> int
> pci_disable_io_method(device_t dev, device_t child, int space)
> {
> - uint16_t command;
>  uint16_t bit;
> - char *error;
> -
> - bit = 0;
> - error = NULL;
>
>  switch(space) {
>  case SYS_RES_IOPORT:
>  bit = PCIM_CMD_PORTEN;
> - error = "port";
>  break;
>  case SYS_RES_MEMORY:
>  bit = PCIM_CMD_MEMEN;
> - error = "memory";
>  break;
>  default:
>  return (EINVAL);
>  }
>  pci_clear_command_bit(dev, child, bit);
> - command = PCI_READ_CONFIG(dev, child, PCIR_COMMAND, 2);
> - if (command & bit) {
> - device_printf(child, "failed to disable %s mapping!\n", error);
> - return (ENXIO);
> - }
>  return (0);
> }
>
>
> -- 
> John Baldwin
>
